+    pruneStale(maxAge = GENESIS_CONFIG.cleanup.staleConnectionTimeout) {
+        const cutoff = Date.now() - maxAge;
+        const removed = [];
+
+        for (const [peerId, peer] of this.peers) {
+            if (peer.lastSeen < cutoff) {
+                this.remove(peerId);
+                removed.push(peerId);
+            }
+        }
+
+        return removed;
+    }
