+    constructor(totalBytes = 0) {
+        super();
+        this.totalBytes = totalBytes;
+        this.bytesTransferred = 0;
+        this.startTime = Date.now();
+        this.lastUpdateTime = Date.now();
+        this.lastBytesTransferred = 0;
+    }
