+            const modelStore = tx.objectStore('models');
+            modelStore.put({
+                id: modelId,
+                data,
+                hash: manifest.integrity?.merkleRoot || 'unknown',
+                size: data.byteLength || data.length,
+                lastAccess: Date.now(),
+                cachedAt: Date.now(),
