+        return new Promise((resolve, reject) => {
+            const tx = this.db.transaction('chunks', 'readwrite');
+            const store = tx.objectStore('chunks');
+            store.put({
+                id: `${modelId}:${chunkIndex}`,
+                modelId,
+                chunkIndex,
+                data,
+                hash,
+                cachedAt: Date.now(),
+            });
